mapper.select:
SELECT a.* FROM animes a
WHERE a.deleted = 0

    AND (a.title LIKE CONCAT('%', #{keyword}, '%') 
         OR a.title_jp LIKE CONCAT('%', #{keyword}, '%')
         OR a.description LIKE CONCAT('%', #{keyword}, '%')
         OR a.studio LIKE CONCAT('%', #{keyword}, '%'))


    AND a.release_year = #{year}


    AND a.status = #{status}


    AND a.studio LIKE CONCAT('%', #{studio}, '%')


    AND a.nationality = #{nationality}


    AND a.anime_type = #{animeType}

ORDER BY 


            a.average_rating DESC, a.rating_count DESC


            a.created_at DESC


            a.id DESC


LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM animes a
WHERE a.deleted = 0

    AND (a.title LIKE CONCAT('%', #{keyword}, '%') 
         OR a.title_jp LIKE CONCAT('%', #{keyword}, '%')
         OR a.description LIKE CONCAT('%', #{keyword}, '%')
         OR a.studio LIKE CONCAT('%', #{keyword}, '%'))


    AND a.release_year = #{year}


    AND a.status = #{status}


    AND a.studio LIKE CONCAT('%', #{studio}, '%')


    AND a.nationality = #{nationality}


    AND a.anime_type = #{animeType}
